/*
 * Auto-block for the "${blockName}" block — builds it from page content automatically.
 * Wire it into buildAutoBlocks(main) in scripts/scripts.js:
 *   import buildAutoBlock from './auto-blocks/${blockName}.js';
 *   buildAutoBlock(main);
 */
import { buildBlock } from '../scripts.js';

export default function buildAutoBlock(main) {
  // Example: wrap the first section into a `${blockName}` block when a condition holds.
  const section = main.querySelector(':scope > div');
  if (!section) return;
  const block = buildBlock('${blockName}', { elems: [...section.children] });
  section.prepend(block);
}

/* ${blockName} — EDS block backed by the @dropins/${dropin} drop-in (Commerce SaaS). */
import { initializers } from '@dropins/tools/initializer.js';
import { render as provider } from '@dropins/${dropin}/render.js';

export default async function decorate(block) {
  block.classList.add('${blockName}');
  // Mount the drop-in. Import the specific container from @dropins/${dropin}
  // (see the boilerplate-commerce docs) and render it into `block`.
  await initializers.mountImmediately(provider, {});
}

/* ${blockName} drop-in block — scoped to .${blockName} (eds/block-css-scope). */
.${blockName} {
  display: grid;
  gap: var(--spacing-m, 16px);
}

